-- Apex Advantage — DPE Question Bank Expansion, Batch 1 of ~4 (v10)
--
-- The Checkride Prep Pack launched with 72 DPE questions across 9
-- categories (see supabase-portal-schema-v5.sql). This is the first of
-- several batches expanding that bank toward ~250 questions total,
-- matching the marketing copy's "72 fully developed oral exam
-- questions" claim which needs to become true before it's published
-- more broadly.
--
-- Target category sizes (existing count -> target):
--   eligibility     8  -> 20   (not in this batch)
--   airworthiness   8  -> 20   (not in this batch)
--   privileges      8  -> 30   (not in this batch; covers "Regulations")
--   airspace        8  -> 30   (+13 in this batch)
--   weather         8  -> 30   (+15 in this batch)
--   performance     8  -> 20   (not in this batch)
--   aeromedical     8  -> 8    (unchanged — not a target category)
--   crosscountry    8  -> 25   (not in this batch)
--   emergency       8  -> 8    (unchanged — not a target category)
--   aircraft-systems 0 -> 25   (+12 in this batch, NEW category)
--   adm             0  -> 40   (+10 in this batch, NEW category)
--
-- This batch focuses on Weather, Airspace, Aircraft Systems, and ADM
-- per the content brief, since those are where applicants most
-- commonly struggle in a real oral exam. Every question was checked
-- against the existing 72 for topic overlap before being written.
--
-- "aircraft-systems" maps to ACS Area of Operation I, Task G
-- (Operation of Systems) -- previously uncovered by this bank.
-- "adm" (Aeronautical Decision-Making & Risk Management) maps to the
-- ACS Special Emphasis Areas -- also previously uncovered as its own
-- category, though touched on tangentially inside "emergency" and
-- "aeromedical."
--
-- Run this in the Supabase SQL editor, after supabase-portal-schema-v9.

insert into public.dpe_categories (id, label, section_label, intro, sort_order) values
  ('aircraft-systems', 'Aircraft Systems', 'Section 11', 'This section tests whether you understand how your aircraft''s systems actually work well enough to recognize a failure, diagnose it, and respond correctly — not just name the parts. DPEs use these questions to see whether "systems knowledge" translates into an actual troubleshooting process under pressure.', 9),
  ('adm', 'Aeronautical Decision-Making & Risk Management', 'Section 12', 'ADM questions are rarely their own isolated section in a real oral exam — examiners weave them through every other topic. This section tests the judgment layer underneath all the technical knowledge: can you actually assess risk, resist pressure, and make a defensible go/no-go call in real time.', 10);

insert into public.dpe_questions (id, category, question, model_answer, common_mistakes, dpe_evaluating, acs_reference, real_world_application, is_scenario, scenario_order, sort_order) values

  -- ═══════════════════ WEATHER (+15) ═══════════════════
  ('wx-9', 'weather', 'You call for a standard weather briefing the morning of a 100-mile VFR cross-country and the briefer mentions an AIRMET Sierra for IFR conditions along your route after 2 PM. Your ETA at the destination is 1 PM. Do you go, and how does this change your planning?', 'AIRMET Sierra covers IFR ceilings/visibility and mountain obscuration. Since your ETA precedes the AIRMET''s stated onset, the flight may be reasonable — but only if you build in a real safety margin, monitor conditions in flight, and set a firm personal decision point rather than treating the forecast time as a guarantee.', 'Treating the AIRMET''s stated onset time as a hard guarantee that conditions won''t arrive early, or ignoring the AIRMET entirely because your ETA is technically before it.', 'Whether you treat forecast timing as probabilistic guidance requiring a buffer and an in-flight decision point, not a fixed contract.', 'Area of Operation I, Task C — Weather Information (Risk Management).', 'Weather does not respect forecast timestamps — pilots who build in a buffer and a real decision point avoid getting caught by conditions that arrive earlier than an AIRMET''s onset time suggests.', true, null, 8),
  ('wx-10', 'weather', 'During your preflight weather briefing, the briefer tells you there''s a SIGMET for severe turbulence along a portion of your route at your planned cruising altitude. What are your options, and how do you decide between them?', 'Options include changing altitude if a smoother layer is reported or forecast, delaying departure, rerouting around the affected area, or canceling. Weigh your aircraft''s capability, your own experience and comfort level, the fuel a longer route would require, and whether current PIREPs actually support or contradict the SIGMET before choosing.', 'Assuming a SIGMET is optional information for light aircraft since it''s "for airliners," or committing to one option without checking whether current PIREPs still support the forecast.', 'Whether you actually generate and weigh real alternatives rather than making a single reflexive go/no-go call.', 'Area of Operation I, Task C — Weather Information (Knowledge and Risk Management).', 'SIGMETs cover hazards significant to all aircraft, including light GA — dismissing one because it feels airline-focused is a documented contributor to turbulence-related accidents.', true, null, 9),
  ('wx-11', 'weather', 'You''re planning a flight and the forecast calls for a temperature/dew point spread of 2 degrees at your departure airport this evening. What does that tell you, and how does it affect your planning?', 'A narrow, closing temperature/dew point spread signals a high likelihood of fog or low clouds forming, especially overnight under clear skies with calm wind (radiation fog). If departing at night or early morning, expect possible IFR conditions and plan an alternate or delay accordingly.', 'Not connecting the spread to actual go/no-go risk, or assuming the current METAR will still be valid by departure time.', 'Whether you can translate a raw numeric fact into an operational forecast of a real hazard.', 'Area of Operation I, Task C — Weather Information (Knowledge).', 'This is one of the most reliable predictors of radiation fog, and it catches pilots who only check the current METAR rather than the closing trend.', true, null, 10),
  ('wx-12', 'weather', 'You notice a stationary front is draped directly across your route on the surface analysis chart. What kind of weather should you expect, and why might it persist for days?', 'A stationary front sits where two air masses meet without either advancing. Expect widespread cloudiness, prolonged precipitation, and reduced visibility along the front — potentially for several days, since neither air mass has enough strength to displace the other.', 'Confusing a stationary front''s slow, lingering weather with the shorter-lived, more violent weather typical of a fast-moving cold front.', 'Whether you understand that front type changes both the expected weather and how long it''s likely to last, which matters for trip planning.', 'Area of Operation I, Task C — Weather Information (Knowledge).', 'A stationary front can scrub a multi-day trip since it may not clear on your timeline, unlike a fast-moving front you might reasonably just wait out for a few hours.', true, null, 11),
  ('wx-13', 'weather', 'Approach control advises of low-level wind shear reported by a departing aircraft. How does that change your approach and landing plan?', 'Expect airspeed and altitude fluctuations on approach. Carry extra airspeed margin above your normal approach speed, be prepared to execute a go-around at the first sign of an unstabilized approach, and consider whether conditions actually warrant delaying until the shear passes.', 'Treating a wind shear PIREP as something to just "power through" rather than adjusting approach speed and lowering your go-around threshold.', 'Whether you translate a hazard report into concrete changes in airspeed, configuration, and decision thresholds, not just verbal acknowledgment.', 'Area of Operation I, Task C — Weather Information (Risk Management).', 'Low-level wind shear is a leading cause of loss-of-control accidents on approach — a rehearsed response protects you, not just awareness that the hazard exists.', true, null, 12),
  ('wx-14', 'weather', 'What''s the difference between a surface analysis chart and a prognostic (prog) chart, and when would you use each during flight planning?', 'A surface analysis chart shows actual observed conditions — fronts and pressure systems — at a specific past time. A prog chart forecasts expected conditions at a future time. Use the surface analysis to understand what''s happening now and how systems have been moving, and the prog chart to anticipate what your route will look like at your planned departure and arrival times.', 'Using only the prog chart without checking the surface analysis to sanity-check how accurately recent forecasts have actually verified.', 'Whether you understand these products as complementary — current truth versus future expectation — rather than interchangeable.', 'Area of Operation I, Task C — Weather Information (Knowledge).', 'Comparing today''s prog chart against yesterday''s actual outcome tells you how much to trust today''s forecast for your flight.', false, null, 13),
  ('wx-15', 'weather', 'You get a weather briefing showing VFR conditions at your destination, but a PIREP twenty minutes old reports a ceiling of 1,500 feet broken along your route — lower than forecast. How do you reconcile the two, and what do you do?', 'A recent PIREP is real-time ground truth and generally takes priority over an older forecast. The discrepancy suggests conditions may be deteriorating faster than forecast, so get an updated briefing, watch for additional PIREPs, and be prepared to delay, reroute, or turn back rather than trusting the original forecast.', 'Discarding the PIREP because "the forecast still says VFR," rather than treating a specific, recent observation as more reliable than an aging general forecast.', 'Whether you appropriately weight actual, current observations over an aging forecast when the two conflict.', 'Area of Operation I, Task C — Weather Information (Risk Management).', 'Forecasts are best-guess predictions; PIREPs are what''s actually happening right now — trusting real-time data over yesterday''s forecast is exactly what examiners want to see.', true, null, 14),
  ('wx-16', 'weather', 'What is the difference between prevailing visibility and flight visibility, and why does that distinction matter to a VFR pilot?', 'Prevailing visibility is the greatest horizontal visibility observed over at least half the horizon circle at the reporting station on the ground. Flight visibility is the average forward horizontal distance from the cockpit at which prominent objects can be seen and identified in flight. VFR minimums are based on flight visibility, which you must judge yourself and which may differ from what''s reported at a nearby station.', 'Assuming the reported ground visibility at the nearest station automatically matches what you''ll experience in flight, especially at altitude or in a haze layer.', 'Whether you understand that VFR compliance rests on your own in-flight judgment, not just a number pulled from a METAR.', 'Area of Operation I, Task C — Weather Information (Knowledge).', 'You are legally responsible for your own flight visibility judgment call, even when a nearby METAR shows a different number.', false, null, 15),
  ('wx-17', 'weather', 'You''re on a VFR cross-country and notice towering cumulus building rapidly ahead of you, though no SIGMET has been issued yet. What do you do?', 'Treat rapidly building towering cumulus as a real, developing hazard regardless of whether an official product has caught up to it yet. Increase your distance from the buildup, consider a route or altitude change, and be ready to divert or land short rather than attempting to fly near or through it.', 'Waiting for official confirmation — a SIGMET or AIRMET — before treating visibly developing weather as a threat.', 'Whether you rely on your own observation and judgment in real time rather than only reacting to official products, which always lag actual conditions.', 'Area of Operation I, Task C — Weather Information (Risk Management).', 'Convective weather can develop faster than the forecast products describing it — what you see out the windscreen right now is more current than any SIGMET.', true, null, 16),
  ('wx-18', 'weather', 'What is virga, and why can it be deceptive to a pilot flying beneath it?', 'Virga is precipitation that evaporates before reaching the ground, visible as streaks hanging beneath a cloud. It''s deceptive because the evaporative cooling process can produce strong, localized downdrafts and even microbursts beneath it, despite no rain actually reaching the surface.', 'Assuming virga means "no weather hazard here" since no rain is falling at the surface.', 'Whether you know that an absence of surface precipitation doesn''t mean an absence of a real wind hazard.', 'Area of Operation I, Task C — Weather Information (Knowledge).', 'Virga has been a factor in wind-shear-related accidents precisely because pilots assume "dry" means "safe."', false, null, 17),
  ('wx-19', 'weather', 'Center advises of moderate turbulence reported at your altitude ten miles ahead. Walk me through what you actually do in the cockpit over the next few minutes.', 'Slow to maneuvering speed or the aircraft''s recommended turbulence penetration speed, secure loose items and confirm seatbelts are on, consider a smoother altitude if one''s available, and communicate with ATC about the ride and any altitude change request. Be prepared to file a PIREP yourself afterward.', 'Continuing at cruise speed into known turbulence, which raises structural load risk, or acknowledging the report verbally without actually changing anything in the cockpit.', 'Whether you translate a PIREP into a concrete airspeed and configuration change, not just situational awareness.', 'Area of Operation I, Task C — Weather Information (Risk Management).', 'Slowing to maneuvering speed before entering known turbulence is a real structural-safety margin, not a formality — and filing your own PIREP helps the next pilot behind you.', true, null, 18),
  ('wx-20', 'weather', 'What does a forecast''s "chance" versus "likely" probability of thunderstorms mean, and how should that change your planning?', 'These are probability-of-precipitation terms describing forecaster confidence — "chance" generally implies roughly 30-50% probability and "likely" implies roughly 60-70% or higher. A higher stated probability should shift your planning toward a firmer alternate or delay plan rather than assuming the weather will simply avoid you.', 'Treating any probability under 100% as effectively "won''t happen," rather than adjusting your risk tolerance to the stated likelihood.', 'Whether you use probabilistic forecast language to actually calibrate your risk tolerance and contingency planning.', 'Area of Operation I, Task C — Weather Information (Knowledge).', 'A "likely" thunderstorm forecast should change your fuel reserves, alternate selection, and personal go/no-go threshold — treating it the same as a "slight chance" forecast is a common planning error.', false, null, 19),
  ('wx-21', 'weather', 'You picked up your weather briefing three hours before departure. As you''re preflighting the aircraft, do you need to check anything again before you go? Why?', 'Yes — get an updated briefing, or at minimum current METARs, TAFs, and any NOTAMs, TFRs, AIRMETs, or SIGMETs issued since your original briefing. Three hours is enough time for meaningful changes, especially with convective activity or fog development.', 'Treating a morning briefing as valid all day without any update, especially before an afternoon departure.', 'Whether you understand a weather briefing as a snapshot with a shelf life, not a one-time task to check off.', 'Area of Operation I, Task C — Weather Information (Risk Management).', 'Conditions can meaningfully change in just a few hours — a stale briefing is one of the more common, avoidable contributors to weather-related accidents.', true, null, 20),
  ('wx-22', 'weather', 'You check ahead and see the destination airport''s automated weather station (AWOS) is listed as out of service in the NOTAMs. How does that change how you plan the approach and landing?', 'Without a functioning on-field automated weather source, you''ll need current conditions from a nearby reporting station, Flight Service, ATC, or your own in-flight observation. Build in extra margin, since you may be landing with less precise, less current wind and altimeter information than you''d normally have.', 'Not noticing the NOTAM at all, or planning to simply "figure it out" in the pattern without a real alternate information source lined up.', 'Whether you treat a NOTAM about degraded weather-reporting infrastructure as something that actually changes your plan, not just a line item you skimmed.', 'Area of Operation I, Task C — Weather Information (Risk Management).', 'An inoperative AWOS means less precise wind and altimeter data exactly when you need it most — on approach and landing.', true, null, 21),
  ('wx-23', 'weather', 'How do you interpret a ceiling reported as vertical visibility rather than a broken or overcast layer, such as VV004?', 'Vertical visibility describes an indefinite ceiling — typically caused by fog, heavy precipitation, or blowing snow or dust — where the sky is obscured with no distinct cloud base. VV004 means the vertical visibility into the obscuration is 400 feet, which for practical purposes should be treated like a 400-foot ceiling with an additional visibility restriction.', 'Confusing an indefinite ceiling or obscuration with a normal broken or overcast cloud layer, or assuming a vertical visibility report is somehow less restrictive than a stated ceiling.', 'Whether you correctly interpret a less commonly discussed METAR element rather than skipping past it.', 'Area of Operation I, Task C — Weather Information (Knowledge).', 'An indefinite ceiling from obscuration typically comes with poor visibility below it too, not just a low cloud base — a meaningfully more restrictive condition than a normal ceiling at the same height.', false, null, 22),

  -- ═══════════════════ AIRSPACE (+13) ═══════════════════
  ('asp-9', 'airspace', 'You''re approaching Class B airspace and call for a transition. ATC says "standby" and nothing else. You''re now three miles out and closing. Can you enter?', 'No — "standby" is not a clearance. You need an explicit clearance with your call sign before entering Class B. Turn or maneuver to remain clear of the Bravo shelf while maintaining position awareness, and try the call again.', 'Treating a vague or partial response as implied clearance, or continuing straight toward the boundary while waiting for a reply.', 'Whether you know "standby" carries no authorization, and whether you have an actual avoidance plan, not just knowledge of what not to do.', 'Area of Operation I, Task E — National Airspace System (Knowledge and Risk Management).', 'This exact situation is a documented, real cause of Class B pilot deviations — silence isn''t a clearance any more than a wing waggle is.', true, null, 8),
  ('asp-10', 'airspace', 'You want to fly a straight-line transition through Class C airspace without stopping. What do you need, and how is that different from operating within Class B?', 'For Class C you need to establish two-way radio communication with ATC before entering — a specific clearance isn''t required, just acknowledged contact. Class B requires an explicit clearance to enter, a meaningfully higher bar.', 'Assuming Class C requires a clearance the same way Class B does, or entering as soon as you''ve transmitted without any acknowledgment from ATC.', 'Whether you can precisely distinguish "established two-way communication" from "clearance," since confusing the two is a real, documented cause of deviations.', 'Area of Operation I, Task E — National Airspace System (Knowledge).', 'Misunderstanding this distinction is one of the most common airspace-related pilot deviations nationwide.', true, null, 9),
  ('asp-11', 'airspace', 'What is the typical vertical and lateral shape of a Class D surface area, and what happens to that airspace when the tower closes for the night?', 'Class D typically extends from the surface up to 2,500 feet AGL within a 4 nautical mile radius, though exact dimensions vary by airport and are depicted on the chart. When the tower closes, the airspace reverts to whatever class is charted for use during those hours — usually Class E or G — and the two-way radio requirement no longer applies.', 'Assuming Class D requirements still apply after the tower has closed, or not knowing the reversionary airspace class is charted separately.', 'Whether you understand that airspace class can change with the clock, not just with distance from the airport.', 'Area of Operation I, Task E — National Airspace System (Knowledge).', 'Many towered fields become uncontrolled at night, and knowing the correct radio procedures for that reversion matters for both legality and safety.', false, null, 10),
  ('asp-12', 'airspace', 'You''re flying VFR at 4,500 feet and notice you''ve drifted into what appears to be a Restricted Area shown as "cold" on the chart. Are you in violation, and what should you do?', 'If a restricted area is genuinely "cold" (inactive), VFR transit generally isn''t a violation of the designation itself — but you should still have confirmed its status before or during the flight through Flight Service, a briefing, or NOTAMs rather than assuming. If there''s any doubt, exit and route around it.', 'Assuming a restricted area is always "hot," or conversely assuming it''s always safe to transit without ever actually verifying its status for that day and time.', 'Whether you know status must be actively verified rather than assumed either way.', 'Area of Operation I, Task E — National Airspace System (Risk Management).', 'Restricted area status changes by day and even hour — verifying it before flight, not guessing, is what actually keeps you legal and safe.', true, null, 11),
  ('asp-13', 'airspace', 'What is a Mode C veil, and where would you find one?', 'A Mode C veil is the airspace within 30 nautical miles of a Class B primary airport, from the surface up to 10,000 feet MSL, in which an operating Mode C (altitude-encoding) transponder is required regardless of whether you''re actually entering the Class B itself.', 'Assuming the transponder requirement only applies once inside the Class B boundary, rather than across the wider 30 nm veil.', 'Whether you know an equipment requirement can extend well beyond the airspace it''s named after.', 'Area of Operation I, Task E — National Airspace System (Knowledge).', 'You can be in full compliance with Class B entry procedures and still be in violation of the transponder requirement if you''re inside the veil without functioning Mode C.', false, null, 12),
  ('asp-14', 'airspace', 'You''re planning a flight that will pass directly over the top of a Class C airspace at 6,500 feet, above its ceiling, without ever talking to that facility. Is that legal, and is it a good idea?', 'Overflying above the charted lateral boundaries of Class C airspace, above its ceiling, is legal without contacting that facility, since you''re not actually inside the Class C airspace. Whether it''s a good idea depends on traffic density — a busy Class C likely has real traffic climbing or descending near its ceiling that you''d want to be aware of.', 'Assuming any overflight near a Class C requires radio contact regardless of altitude, or conversely ignoring the real traffic-conflict risk just because it''s technically legal.', 'Whether you can separate the legal requirement from the practical safety judgment, which don''t always point to the same answer.', 'Area of Operation I, Task E — National Airspace System (Risk Management).', 'Legal and safe aren''t always identical — recognizing when a technically compliant plan still carries real traffic risk is core PIC judgment.', true, null, 13),
  ('asp-15', 'airspace', 'What is the general purpose of a Military Operations Area (MOA), and what should a VFR pilot do before flying through one?', 'An MOA defines airspace used for military training activities such as air combat maneuvers, with published vertical limits shown on the chart. VFR flight through an active MOA is legal without clearance, but you should check its current status through Flight Service or a briefing and exercise real caution due to high-speed military traffic if you choose to transit while it''s active.', 'Assuming an MOA is entirely off-limits to civilian VFR traffic, or transiting an active MOA with no real situational awareness of the traffic it may contain.', 'Whether you know the legal status (permitted) versus the practical risk (real, and worth actively checking).', 'Area of Operation I, Task E — National Airspace System (Knowledge and Risk Management).', 'MOAs are legal to transit but genuinely hazardous when active — checking status first is the actual safety practice, not just a legal formality.', false, null, 14),
  ('asp-16', 'airspace', 'ATC issues you a heading and altitude that would take you into an adjacent facility''s Class B airspace, but you haven''t been told you''re cleared into that Class B. What do you do?', 'Query ATC before complying if you believe the instruction would put you into Class B airspace without a clearance. As PIC you''re responsible for verifying you have clearance for the airspace you''ll enter — a controller''s instruction doesn''t automatically substitute for that if there''s ambiguity.', 'Blindly following an ATC instruction without recognizing you personally remain responsible for compliance with any airspace requirement it might create.', 'Whether you understand that following ATC instructions doesn''t remove your own responsibility to confirm you''re legally authorized for the airspace involved.', 'Area of Operation I, Task E — National Airspace System (Risk Management).', 'ATC instructions and airspace clearances are related but distinct — a good pilot double-checks rather than assuming one implies the other.', true, null, 15),
  ('asp-17', 'airspace', 'You''re looking at a sectional chart and see a dashed magenta line around an airport that has no operating control tower. What airspace class does that indicate, and what does it mean for radio procedures?', 'A dashed magenta line indicates a Class E surface area extending down to the surface at that airport, typically established to support instrument approaches. Since there''s no tower, there''s no mandatory two-way radio requirement to enter, but you should still use the appropriate common traffic advisory frequency, and be aware weather minimums for that surface area apply for VFR operations.', 'Confusing a dashed magenta Class E surface area with a dashed blue Class D boundary, which does require an operating tower and two-way radio contact.', 'Whether you can correctly read chart symbology to determine airspace class at an unfamiliar, non-towered field.', 'Area of Operation I, Task E — National Airspace System (Knowledge).', 'Misreading chart symbology at an unfamiliar airport can lead a pilot to either unnecessarily call a nonexistent tower or miss a weather-minimum requirement that actually applies.', true, null, 16),
  ('asp-18', 'airspace', 'What is the purpose of an Air Defense Identification Zone (ADIZ), and when would a VFR pilot actually encounter one?', 'An ADIZ requires an activated flight plan (or equivalent), a functioning two-way radio, and typically a Mode C transponder for any aircraft entering — largely for national security identification, layered on top of, not replacing, normal airspace class rules. You''d encounter one along international borders, such as portions of the coast or near Mexico or Canada.', 'Treating an ADIZ requirement as optional for VFR flights, or not filing and activating a flight plan before entry.', 'Whether you know this is a security-driven requirement distinct from ordinary airspace class rules.', 'Area of Operation I, Task E — National Airspace System (Knowledge).', 'Failing to comply with ADIZ procedures can trigger a real intercept, not just a paperwork violation.', false, null, 17),
  ('asp-19', 'airspace', 'You''re flying near the surface where the base of the overlying Class E airspace is designated 700 feet AGL. What airspace are you actually in below that, and what are the weather minimums?', 'Below the designated 700-foot (or 1,200-foot) floor of Class E, if not otherwise controlled, the airspace is typically Class G, which carries different weather minimums than Class E. The exact minimums depend on day versus night and altitude, so know which regime you''re actually in before relying on Class E minimums.', 'Applying Class E weather minimums to a flight that''s actually below the Class E floor, in Class G airspace with different requirements.', 'Whether you can identify which airspace class you''re actually in based on altitude, not just assume the nearest labeled class applies everywhere.', 'Area of Operation I, Task E — National Airspace System (Knowledge).', 'Flying low near an unfamiliar area without knowing the exact floor of controlled airspace can mean you''re either more or less restricted than you assumed.', true, null, 18),
  ('asp-20', 'airspace', 'What kind of information can you find published for a specific Class B airspace area beyond just its lateral and vertical dimensions, and why does an applicant need to check it before flying near one?', 'Each Class B airspace area has specific published procedures, including VFR transition routes and, in some cases, VFR corridors, with specific entry and exit points and frequencies unique to that facility — these vary significantly between different Class B areas and aren''t standardized nationwide beyond the basic entry requirements.', 'Assuming all Class B airspace areas work identically, without checking the specific published procedures for the one you''re actually flying near.', 'Whether you know to research the specific facility rather than relying on generic Class B knowledge alone.', 'Area of Operation I, Task E — National Airspace System (Knowledge).', 'A VFR transition route that works at one Class B airport may not exist at all at another — generic knowledge isn''t a substitute for checking the specific chart and procedures.', false, null, 19),
  ('asp-21', 'airspace', 'You''re on a long cross-country and realize your planned route will clip the edge of a Class B airspace''s Mode C veil without you actually entering the Class B itself. What, if anything, do you need to do?', 'Inside the Mode C veil but outside the Class B lateral boundaries, you don''t need an ATC clearance, but you do need an operating Mode C transponder. Confirm your transponder is on and functioning correctly, since this requirement applies regardless of whether you ever actually enter the Class B airspace.', 'Believing that staying outside the Class B boundary means no equipment requirements apply at all.', 'Whether you separate the equipment requirement (veil-based) from the clearance requirement (boundary-based), since they''re triggered by different things.', 'Area of Operation I, Task E — National Airspace System (Knowledge).', 'This is a common point of confusion — knowing the veil''s requirement is purely equipment-based, not clearance-based, keeps you legal without over- or under-complying.', true, null, 20),

  -- ═══════════════════ AIRCRAFT SYSTEMS (+12, new category) ═══════════════════
  ('acsys-1', 'aircraft-systems', 'During your engine runup, you switch from BOTH to the LEFT magneto and notice a larger-than-expected RPM drop, right at the edge of your POH''s allowable limit. What does this tell you, and what''s your decision?', 'A magneto check verifies each ignition system independently. An RPM drop at or near the maximum allowable limit suggests that magneto or plug set is running rougher than normal — possibly fouled plugs, a timing issue, or an actual magneto problem. At the edge of the limit, lean the mixture briefly to help burn off possible fouling and recheck; if the drop still exceeds the limit or the engine runs rough on that magneto, the aircraft isn''t airworthy for departure until a mechanic addresses it.', 'Accepting a borderline result without any troubleshooting step, like a brief mixture lean-out to clear fouling, or launching anyway because the numbers were "close enough."', 'Whether you know a specific, correct troubleshooting step for a marginal mag check, not just the pass/fail number itself.', 'Area of Operation I, Task G — Operation of Systems (Knowledge and Risk Management).', 'A dual ignition system exists specifically so a single magneto failure doesn''t strand you — but only if you actually catch a marginal result on the ground instead of finding out in flight.', true, null, 0),
  ('acsys-2', 'aircraft-systems', 'What is the difference between how a carbureted engine and a fuel-injected engine are each susceptible to icing, and how do you handle each?', 'Carbureted engines are susceptible to carburetor ice, caused by the cooling effect of fuel vaporization and pressure drop in the venturi, even in visibly clear, above-freezing air with visible moisture present; carb heat is the remedy. Fuel-injected engines don''t get carburetor ice the same way since fuel is injected directly, but can be susceptible to impact icing on the induction air intake in visible moisture, for which an alternate air source is provided.', 'Assuming a fuel-injected engine has no icing vulnerability at all, or using carb heat procedures on an aircraft that actually has an alternate air system instead.', 'Whether you know your specific aircraft''s induction system and the correct icing remedy for it, not a generic answer that might not apply.', 'Area of Operation I, Task G — Operation of Systems (Knowledge).', 'Applying the wrong remedy — or none — because you assumed your aircraft''s induction system works like a different one you''ve flown is a real, avoidable risk.', false, null, 1),
  ('acsys-3', 'aircraft-systems', 'During cruise flight you notice the oil pressure gauge reading in the yellow arc, but oil temperature is normal. What does that combination suggest, and what do you do?', 'Low oil pressure with normal temperature can suggest a pressure-sensing or regulation issue, or early-stage pump or line trouble, rather than a quantity or overheat problem, which would typically show elevated temperature too. Reduce power to minimize stress on the engine, watch for any change, and land as soon as practical since oil pressure is critical to engine health and can precede a rapid, serious failure.', 'Ignoring an abnormal-but-not-yet-critical reading because "the other gauge looks fine," rather than treating any abnormal primary engine indication seriously.', 'Whether you interpret combined instrument readings together rather than checking each gauge in isolation.', 'Area of Operation I, Task G — Operation of Systems (Risk Management).', 'Engine gauges are meant to be read together — a normal-looking temperature doesn''t clear a low pressure reading, and treating them as related warnings buys you time before a real failure.', true, null, 2),
  ('acsys-4', 'aircraft-systems', 'What is the purpose of the vacuum system in a typical training aircraft, and which instruments depend on it?', 'The vacuum system, driven by an engine-mounted pump, provides suction to spin the gyros in the attitude indicator and heading indicator in most conventional analog panels. The turn coordinator is typically electrically powered instead, providing a useful cross-check if the vacuum system fails.', 'Assuming all gyroscopic instruments share the same power source, missing that the turn coordinator''s separate electrical power is exactly what makes it a useful failure cross-check.', 'Whether you know which instruments would fail together versus which would remain reliable in a vacuum failure, since that''s what actually matters in an emergency.', 'Area of Operation I, Task G — Operation of Systems (Knowledge).', 'Recognizing a vacuum failure quickly depends on knowing the turn coordinator is your independent backup — pilots who don''t know this cross-check can be slower to catch a failed attitude indicator.', false, null, 3),
  ('acsys-5', 'aircraft-systems', 'You lose the vacuum pump in flight, in VFR conditions. What are the practical implications, and how would this be different if you were in IMC?', 'In VFR conditions the attitude and heading indicators will slowly fail, typically drifting or toppling, but you can continue safely using outside visual references along with the electrically powered turn coordinator, magnetic compass, and other backups. In IMC, this becomes a serious emergency requiring partial-panel flying skills to maintain control using the remaining reliable instruments.', 'Treating a vacuum failure as equally serious regardless of conditions, when the actual risk level depends heavily on whether outside visual references are available.', 'Whether you understand the same mechanical failure carries dramatically different real-world risk depending on the flight conditions you''re in.', 'Area of Operation I, Task G — Operation of Systems (Risk Management).', 'The same failure that''s a minor inconvenience in VFR can be a life-threatening emergency in IMC — exactly why instrument-rated pilots specifically train for partial-panel flying.', true, null, 4),
  ('acsys-6', 'aircraft-systems', 'What''s the difference between a fixed-pitch and a constant-speed propeller in terms of how you control engine performance?', 'A fixed-pitch propeller''s blade angle is set, and pitch effectively changes only with airspeed and RPM driven by the throttle alone. A constant-speed propeller adds a propeller control, governor-driven, letting you independently set RPM while the throttle sets manifold pressure — giving you two separate performance controls that must be managed together correctly, avoiding high manifold pressure with low RPM.', 'Not understanding why constant-speed aircraft require a specific power-setting sequence — RPM before increasing manifold pressure, and manifold pressure before decreasing RPM — to avoid engine stress.', 'Whether you understand not just what the systems are, but why the correct power-lever sequencing procedure exists.', 'Area of Operation I, Task G — Operation of Systems (Knowledge).', 'Mismanaging power lever sequencing on a constant-speed prop can put real mechanical stress on the engine — this isn''t just a checklist habit, it protects the powerplant.', false, null, 5),
  ('acsys-7', 'aircraft-systems', 'You smell an electrical burning odor in the cockpit shortly after turning on the avionics master. What''s your immediate response?', 'Turn off the avionics master, and the battery master too if the smell persists or worsens, since an electrical odor suggests an overheating component or short. Be prepared to use a fire extinguisher if smoke or flame appears, ventilate the cabin if safe to do so, and land as soon as practical.', 'Continuing to troubleshoot avionics with the system still powered rather than removing power first, which is the priority action for an electrical fire indication.', 'Whether your first action is removing electrical power from the suspect system, not continuing to investigate with it still energized.', 'Area of Operation I, Task G — Operation of Systems (Risk Management).', 'An electrical smell is an early warning of a fire that hasn''t fully developed yet — removing power immediately is what actually prevents it from becoming one.', true, null, 6),
  ('acsys-8', 'aircraft-systems', 'What are the two basic types of aircraft fuel systems in terms of how fuel reaches the engine, and what''s the key operational difference a pilot needs to manage?', 'A gravity-feed system relies on fuel tanks mounted above the engine, using gravity alone to deliver fuel with no pump required for normal operation. A pump-fed system relies on an engine-driven pump, typically backed up by an electric auxiliary pump the pilot must manage — for example during takeoff, landing, and fuel tank switching — in case the primary pump fails.', 'Not knowing which type your specific aircraft has, and therefore missing the auxiliary fuel pump procedures that apply to pump-fed systems but not gravity-feed ones.', 'Whether you know your specific aircraft''s fuel system well enough to apply the right procedures, not a generic answer.', 'Area of Operation I, Task G — Operation of Systems (Knowledge).', 'Applying gravity-feed assumptions to a pump-fed aircraft, or vice versa, means missing real procedures like when to turn on the auxiliary fuel pump.', false, null, 7),
  ('acsys-9', 'aircraft-systems', 'Your aircraft has two fuel tanks with a fuel selector, and you notice the engine begins to run rough while established in cruise on the left tank. What''s your immediate troubleshooting sequence?', 'Apply carburetor heat if equipped and appropriate to rule out carb ice, check mixture, verify magnetos and ignition, and check the fuel selector position and quantity, since fuel starvation or contamination from one tank is a common and immediately correctable cause of rough running. Be prepared to execute the appropriate engine-out procedure if it doesn''t resolve.', 'Jumping straight to switching tanks without a logical troubleshooting sequence, or not considering carb ice or mixture first if those are more likely given conditions.', 'Whether you have an actual ordered process for engine roughness rather than a random guess at the first thing that comes to mind.', 'Area of Operation I, Task G — Operation of Systems (Risk Management).', 'A methodical, rehearsed troubleshooting flow is what actually resolves in-flight engine roughness quickly instead of wasting critical altitude and time.', true, null, 8),
  ('acsys-10', 'aircraft-systems', 'What is the purpose of the aircraft''s static system, and what happens to your airspeed and altitude indications if the static port becomes blocked?', 'The static system provides ambient outside air pressure reference to the airspeed indicator, altimeter, and vertical speed indicator. If the static port is blocked, the altimeter will freeze at the altitude where the blockage occurred, the VSI will read zero regardless of actual climb or descent, and the airspeed indicator will become unreliable as you climb or descend from the blocked altitude and pressure.', 'Only knowing the altimeter is affected, without recognizing airspeed and VSI are also compromised by the same blockage.', 'Whether you know all three instruments served by the static system, not just the most obvious one.', 'Area of Operation I, Task G — Operation of Systems (Knowledge).', 'Most trainers have an alternate static source specifically for this failure — knowing when and how to use it depends on recognizing all three affected instruments, not just a frozen altimeter.', false, null, 9),
  ('acsys-11', 'aircraft-systems', 'You''re using the alternate static source after suspecting a blocked primary static port. How should you expect your airspeed and altimeter readings to change, and why?', 'In most light aircraft the alternate static source samples pressure from inside the unpressurized cabin, which typically reads slightly lower than true outside static pressure. This generally causes the altimeter to read slightly high and the airspeed indicator to read slightly differently than normal, in a direction and amount specified in your POH, which you should reference and correct for accordingly.', 'Assuming the alternate static source reads identically to the primary, rather than checking the POH''s specific correction figures.', 'Whether you actually know to reference your own aircraft''s POH correction data rather than assuming a generic answer applies.', 'Area of Operation I, Task G — Operation of Systems (Knowledge).', 'Flying an approach to minimums using an alternate static source without knowing its specific error could mean flying lower or higher than you think.', true, null, 10),
  ('acsys-12', 'aircraft-systems', 'What system provides pitot heat, and under what conditions is failing to use it likely to cause a problem?', 'Pitot heat is an electrically powered heating element in the pitot tube designed to prevent ice or moisture blockage. Failing to use it in visible moisture near or below freezing temperatures — including clouds, precipitation, or a ground deicing scenario — can cause the pitot tube to ice over, leading to unreliable or lost airspeed indication.', 'Only thinking of pitot heat as relevant to instrument flight in the clouds, forgetting it can also matter during a VFR flight through visible moisture at cold temperatures.', 'Whether you recognize the actual trigger conditions — visible moisture plus cold temperature — rather than a vague "use it when it''s cold" answer.', 'Area of Operation I, Task G — Operation of Systems (Knowledge).', 'Losing airspeed indication in actual instrument conditions because pitot heat wasn''t turned on is a real, preventable, and well-documented cause of loss-of-control accidents.', false, null, 11),

  -- ═══════════════════ ADM & RISK MANAGEMENT (+10, new category) ═══════════════════
  ('adm-1', 'adm', 'You''re 20 minutes into a planned 2-hour cross-country when you notice the weather ahead looks worse than forecast. You still have plenty of fuel to continue or return. What''s your decision process?', 'Use a structured process — assess the actual observed conditions against your personal minimums, consider what''s driving any urge to continue, evaluate whether turning back, diverting, or waiting it out is the lowest-risk option, and make the decision early while you still have good options rather than waiting until you''re boxed in.', 'Continuing simply because "we''re already out here," or because turning back feels like admitting failure, rather than evaluating the observed conditions on their own merits.', 'Whether you have and would actually use a real decision framework, and whether you recognize the pressure to continue as a hazard in itself.', 'Special Emphasis Area — Aeronautical Decision-Making and Risk Management (ACS Appendix).', 'Continued VFR flight into deteriorating weather is one of the most consistently fatal accident categories in general aviation — and it''s almost always driven by exactly this kind of "we''re already committed" thinking.', true, null, 0),
  ('adm-2', 'adm', 'You''ve noticed that on your last several flights, you''ve been skipping the passenger safety briefing because you''re flying with the same friend each time and it feels unnecessary. Is this actually a risk, and what''s this pattern called?', 'This is a real risk, and the pattern is often called "normalization of deviance" — the gradual acceptance of skipping a required or recommended step because nothing bad has happened yet, which erodes the habit that actually protects you on the day something does go wrong, like an unfamiliar passenger or an actual emergency where they need to know exit procedures. The fix is treating standard procedures as non-negotiable regardless of how routine a flight feels.', 'Justifying the skipped step by pointing to the fact that nothing bad has happened yet, rather than recognizing that as exactly the mechanism by which the habit erodes.', 'Whether you can recognize a specific, named hazard pattern in your own recent behavior, not just when it''s described abstractly.', 'Special Emphasis Area — Aeronautical Decision-Making and Risk Management (ACS Appendix).', 'Normalization of deviance is a documented contributor to accidents across aviation, from individual GA flights to major airline events — the habit that gets skipped without consequence a hundred times is often the one that matters on the hundred-and-first.', true, null, 1),
  ('adm-3', 'adm', 'Flying single-pilot, you''re simultaneously trying to reprogram the GPS, respond to a frequency change from ATC, and keep an eye out for traffic in a busy pattern. What concept describes managing all of this, and how do you actually prioritize it?', 'This is Single-Pilot Resource Management (SRM) — using all available resources, including automation, checklists, ATC, and your own attention, efficiently to maintain safety with only one pilot on board. Prioritize using an "aviate, navigate, communicate" order: fly the aircraft first, maintain safe navigation and traffic awareness second, and handle communication or programming tasks last, or by delegating them to a more convenient moment such as leveling off or before entering the pattern.', 'Treating all three tasks as equally urgent and attempting them simultaneously, rather than consciously sequencing them by the aviate-navigate-communicate priority.', 'Whether you have an actual, named prioritization framework for task saturation, not just a general sense that you should "manage it."', 'Area of Operation I, Task H — Human Factors (Risk Management) / Special Emphasis Area — Single-Pilot Resource Management.', 'Task saturation in a busy pattern is exactly when aircraft control lapses happen — a real prioritization order is what keeps flying the airplane from ever becoming the thing you deprioritize.', true, null, 2),
  ('adm-4', 'adm', 'What is the difference between a hazard and a risk in the context of aeronautical decision-making, and why does that distinction matter for how you plan a flight?', 'A hazard is a condition or circumstance with the potential to cause harm — thunderstorms along a route, for example — while risk is the assessed likelihood and severity of that hazard actually affecting your specific flight, given your experience, aircraft, and the actual circumstances. Two pilots can face the identical hazard with very different real risk levels depending on their preparation, currency, and options.', 'Treating "hazard identified" as the end of the analysis, without going on to actually assess the resulting risk level for your specific flight.', 'Whether you understand risk assessment as a further step beyond simply naming hazards.', 'Special Emphasis Area — Aeronautical Decision-Making and Risk Management (ACS Appendix).', 'A hazard you''ve identified but not actually assessed for risk hasn''t actually been managed — this distinction is the entire basis of the preflight risk-assessment tools many operators require.', false, null, 3),
  ('adm-5', 'adm', 'You''re using the PAVE checklist to assess risk for an upcoming flight. Walk me through what each letter represents, and give me a real risk factor for each one on a flight you might actually fly.', 'P is Pilot — your own currency, recency, and IMSAFE status. A is Aircraft — its airworthiness, performance for the conditions, and any equipment limitations. V is enVironment — weather, airport conditions, terrain, and airspace. E is External pressures — schedule commitments, passenger expectations, or other pressure to complete the flight as planned. A complete answer names a specific, realistic risk factor under each category rather than just describing the acronym.', 'Reciting what each letter stands for without giving a concrete example of an actual risk factor in each category.', 'Whether you can actually apply the framework to a real flight rather than just recite the mnemonic.', 'Special Emphasis Area — Aeronautical Decision-Making and Risk Management (ACS Appendix).', 'A risk-assessment tool is only useful if you can actually populate it with real, specific answers for the flight in front of you — not just recall the acronym.', true, null, 4),
  ('adm-6', 'adm', 'Your instructor is unavailable and a well-meaning line pilot at the airport offers some advice that contradicts something you were taught in training. How do you handle that, both in the moment and afterward?', 'In the moment, you''re not obligated to act on advice that conflicts with your training or your own judgment as PIC — you can politely decline or defer the decision. Afterward, bring the conversation back to your own instructor to resolve the discrepancy rather than just picking whichever advice you heard most recently or most confidently delivered.', 'Deferring to confidently delivered advice from someone with more apparent experience without verifying it against your own training or the regulations.', 'Whether you''d actually maintain your own judgment as PIC rather than being swayed by social pressure or apparent authority in the moment.', 'Area of Operation I, Task H — Human Factors (Risk Management).', 'Hangar-flying advice is often well-intentioned but sometimes wrong or aircraft-specific in ways that don''t apply to you — PIC authority means the decision is still yours to make.', true, null, 5),
  ('adm-7', 'adm', 'You''ve flown the same short cross-country route dozens of times and know it well. On today''s flight, what''s the actual risk of that familiarity, and how do you guard against it?', 'Familiarity can lead to complacency — skipping or rushing checklist items, relying on memory of "how it usually goes" rather than checking today''s actual conditions, and reduced vigilance for changes like a new obstacle, different traffic, or shifted weather, because the route feels routine. Guard against it by treating every flight, including a familiar one, with the same checklist discipline and current information as if it were new.', 'Assuming familiarity is purely a safety benefit with no offsetting risk.', 'Whether you recognize complacency itself as a genuine hazard, not just a comfortable byproduct of experience.', 'Special Emphasis Area — Aeronautical Decision-Making and Risk Management (ACS Appendix).', 'A disproportionate number of accidents happen on routes and at airports pilots know well, precisely because familiarity erodes the vigilance a truly unfamiliar situation would demand.', true, null, 6),
  ('adm-8', 'adm', 'What is "get-there-itis," and what are some practical, concrete steps a pilot can take to guard against it before a flight even begins?', 'Get-there-itis is the tendency to continue a flight as planned despite mounting evidence it should be changed or canceled, driven by external pressure to arrive on schedule. Practical guards include setting personal minimums in advance, before the pressure is present, building schedule flexibility with a backup plan, and pre-committing to specific decision points so the in-the-moment decision has effectively already been made in a calmer state of mind.', 'Describing get-there-itis only as a concept without naming concrete, actionable steps to prevent it.', 'Whether you have real, practiced strategies rather than just an awareness that the hazard exists.', 'Special Emphasis Area — Aeronautical Decision-Making and Risk Management (ACS Appendix).', 'Personal minimums set calmly on the ground, before a trip, are far more reliable than a decision made in the airplane under real time and social pressure.', false, null, 7),
  ('adm-9', 'adm', 'You''re the pilot in command with a passenger who is anxious about flying and keeps asking you to "just get it over with" as weather conditions marginally worsen. How do you manage this?', 'As PIC, the decision remains yours based on the actual conditions and your own risk assessment, not the passenger''s emotional state or requests. Acknowledge their anxiety, explain your reasoning calmly, and don''t let their pressure to rush substitute for your own honest evaluation of whether to continue, delay, or divert.', 'Letting a passenger''s emotional pressure influence a decision that should be based purely on conditions and risk assessment.', 'Whether you''d maintain PIC authority and judgment under real interpersonal pressure, not just textbook pressure.', 'Area of Operation I, Task H — Human Factors (Risk Management).', 'External pressure doesn''t only come from schedules — a passenger''s anxiety or impatience is a real-world pressure source that has influenced poor go/no-go decisions.', true, null, 8),
  ('adm-10', 'adm', 'What is the 5P model — Plan, Plane, Pilot, Passengers, Programming — and how is it different from PAVE?', 'The 5P model organizes risk assessment around five specific checkpoints applied repeatedly throughout a flight — at planning, before departure, before takeoff, and en route — rather than PAVE''s single-pass framework. "Programming" specifically refers to your avionics and automation setup and its own risk of distraction or mismanagement, an element PAVE doesn''t explicitly separate out.', 'Treating 5P and PAVE as identical or redundant, missing that 5P is designed to be reapplied at multiple points in a single flight rather than used once during planning.', 'Whether you know more than one risk-management framework and understand what''s actually distinct about each, rather than memorizing one and assuming it covers everything.', 'Special Emphasis Area — Aeronautical Decision-Making and Risk Management (ACS Appendix).', 'Risk isn''t static across a flight — reapplying a framework like 5P at multiple checkpoints catches new risk factors that appear after you''ve already committed to going.', false, null, 9);
